const fields = $input.item.json || {};
const recordId = $input.item.json.id;
const relanceCount = fields.relance_count ?? 0;
const newCount = relanceCount + 1;
const nomClient = fields.nom_prospect ?? 'Client';
const emailClient = fields.email ?? '';
const trajet = (fields.ville_depart ?? '?') + ' → ' + (fields.ville_arrivee ?? '?');
const newStatut = relanceCount === 0 ? 'Relance 1' : 'Relance 2';
const nextDate = new Date();
nextDate.setDate(nextDate.getDate() + 7);
const prochaineRelance = newCount < 2 ? nextDate.toISOString() : null;
const subject = relanceCount === 0
  ? 'Rappel : votre devis NeoTravel est disponible'
  : 'Dernière relance — votre devis NeoTravel';
const html = '<p>Bonjour ' + nomClient + ',</p><p>Nous revenons vers vous concernant votre demande de transport pour le trajet <strong>' + trajet + '</strong>.</p><p>Répondez à cet email ou contactez-nous pour confirmer votre réservation.</p><p>Cordialement,<br>L\'équipe NeoTravel</p>';

// Extract linked Devis record ID (first linked devis on this lead)
const devisLinked = fields['Devis'] || [];
const devisRecordId = Array.isArray(devisLinked) && devisLinked.length > 0 ? devisLinked[0].id : null;

return { recordId, emailClient, subject, html, newStatut, newRelanceCount: newCount, prochaineRelance, devisRecordId };
